/**
 * SPEC-022: visibilidad del modo degradado en la sección Grabación (mitad
 * renderer): Alert informativo con copy literal solo durante la sesión
 * degradada, líneas sin hablante sin errores, y nunca en sesión normal.
 * Generated by QA Dev agent.
 *
 * Montada vía InterviewDetailPage (mocks del spike, arnés SPEC-015) con la
 * travesía del aviso de consentimiento (SPEC-019). Las etiquetas genéricas
 * "Tú"/"Interlocutor N" del Sheet y del export están fijadas por las suites
 * de SPEC-017 (referenciadas en el map).
 */
import { act, render, screen, waitFor, within, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { Toaster } from '@/components/ui/sonner'
import { TooltipProvider } from '@/components/ui/tooltip'
import { InterviewDetailPage } from '@/pages/InterviewDetailPage'
import {
  acquireMicrophoneStream,
  acquireSystemAudioStream,
  listAudioInputDevices
} from '@/services/captureService'
import { getPermissionsStatus } from '@/services/permissionsService'
import type { Company, Interview } from '@/types/domain'
import type { StopResult } from '@/types/audio'
import { createFakeAudioStream } from '../../helpers/fakeMediaStream'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

vi.mock('@/services/permissionsService', () => ({
  getPermissionsStatus: vi.fn(),
  requestMicrophoneAccess: vi.fn(),
  openPrivacySettings: vi.fn()
}))

vi.mock('@/services/captureService', () => ({
  DEFAULT_DEVICE_ID: '__default__',
  acquireMicrophoneStream: vi.fn(),
  acquireSystemAudioStream: vi.fn(),
  listAudioInputDevices: vi.fn(),
  stopStream: vi.fn()
}))

vi.mock('@/services/wavRecorderService', () => ({
  CAPTURE_SAMPLE_RATE: 16000,
  WavRecorderService: class {
    start = vi.fn()
    stop = vi.fn()
    getLevels = vi.fn(() => ({ microphone: 0, system: 0 }))
    readonly durationSeconds = 0
    readonly samplesWritten = 0
  }
}))

let mockApi: MockApiHandle

const DEGRADED_COPY =
  'Transcribiendo sin atribución de hablante. La transcripción y el asistente siguen funcionando.'

const COMPANY: Company = {
  id: 'c-1',
  name: 'Acme Corp',
  website: null,
  linkedinUrl: null,
  createdAt: '2026-07-02T12:00:00.000Z',
  updatedAt: '2026-07-02T12:00:00.000Z'
}

const INTERVIEW: Interview = {
  id: 'i-1',
  discoveryId: 'd-1',
  companyId: 'c-1',
  contactIds: [],
  interviewGroupId: null,
  templateId: null,
  title: 'Discovery con Acme',
  status: 'draft',
  scriptMarkdown: null,
  objectives: [],
  wavPath: null,
  transcriptPath: null,
  createdAt: '2026-07-04T10:00:00.000Z',
  updatedAt: '2026-07-04T10:00:00.000Z'
}

const STOP_RESULT: StopResult = {
  filePath: '/tmp/maurya-recordings/entrevista.wav',
  durationSeconds: 30,
  sizeBytes: 44,
  sampleRate: 16000,
  channels: 2,
  transcriptPath: '/tmp/maurya-recordings/entrevista.transcript.json',
  latency: null,
  interview: {
    ...INTERVIEW,
    wavPath: '/tmp/maurya-recordings/entrevista.wav',
    transcriptPath: '/tmp/maurya-recordings/entrevista.transcript.json',
    status: 'recorded'
  }
}

function renderDetail(): RenderResult {
  return render(
    <TooltipProvider>
      <MemoryRouter initialEntries={['/discoveries/d-1/companies/c-1/interviews/i-1']}>
        <Routes>
          <Route
            path="/discoveries/:discoveryId/companies/:companyId/interviews/:interviewId"
            element={<InterviewDetailPage />}
          />
        </Routes>
      </MemoryRouter>
      <Toaster />
    </TooltipProvider>
  )
}

/** Arranca la grabación atravesando el aviso de consentimiento (SPEC-019). */
async function startRecording(user: ReturnType<typeof userEvent.setup>): Promise<void> {
  await user.click(await screen.findByRole('button', { name: 'Iniciar grabación' }))
  const consent = await screen.findByRole('alertdialog')
  await user.click(within(consent).getByRole('button', { name: 'Entendido, iniciar grabación' }))
  await screen.findByRole('button', { name: 'Detener' })
}

/** Simula el paso a modo degradado emitido por main (SPEC-022). */
function emitDegradedActive(): void {
  act(() => {
    mockApi.emitTranscriptionStatus({ status: 'active', degraded: true })
  })
}

beforeEach(() => {
  vi.clearAllMocks()
  window.localStorage.clear()
  mockApi = installMockApi()
  vi.mocked(mockApi.api.db.getCompany).mockResolvedValue({ ok: true, data: COMPANY })
  vi.mocked(mockApi.api.db.getInterview).mockResolvedValue({ ok: true, data: INTERVIEW })
  vi.mocked(mockApi.api.llm.getStatus).mockResolvedValue({
    ok: true,
    data: { hasAnthropicKey: true }
  })
  vi.mocked(listAudioInputDevices).mockResolvedValue([])
  vi.mocked(getPermissionsStatus).mockResolvedValue({
    microphone: 'granted',
    systemAudio: 'granted'
  })
  vi.mocked(acquireMicrophoneStream).mockResolvedValue(createFakeAudioStream().stream)
  vi.mocked(acquireSystemAudioStream).mockResolvedValue(createFakeAudioStream().stream)
  vi.mocked(mockApi.api.recording.stop).mockResolvedValue(STOP_RESULT)
})

describe('RecordingSection (degradación SPEC-022)', () => {
  // SPEC-022 · AC-06
  it('shows the informative degraded alert with the literal copy while the degraded session lasts and hides it when the recording stops', async () => {
    const user = userEvent.setup()
    renderDetail()
    await startRecording(user)

    emitDegradedActive()

    const alert = await screen.findByTestId('transcription-degraded-alert')
    expect(alert).toHaveTextContent(DEGRADED_COPY)
    // No destructivo: es información, nada ha fallado de forma irrecuperable
    expect(alert).not.toHaveClass('text-destructive')

    // Permanece mientras dura la sesión (más eventos degradados no lo quitan)
    act(() => {
      mockApi.emitTranscriptionResult({
        channel: 'mic',
        text: 'seguimos hablando',
        startMs: 1000,
        endMs: 2000,
        receivedAtMs: 2100,
        isFinal: true,
        speaker: null,
        offsetSeconds: 1
      })
    })
    expect(screen.getByTestId('transcription-degraded-alert')).toBeInTheDocument()

    // Al terminar la sesión de grabación el Alert desaparece
    await user.click(screen.getByRole('button', { name: 'Detener' }))
    await waitFor(() =>
      expect(screen.queryByTestId('transcription-degraded-alert')).not.toBeInTheDocument()
    )
  })

  // SPEC-022 · AC-07
  it('renders degraded final lines with the generic labels and no speaker chip, without errors', async () => {
    const user = userEvent.setup()
    renderDetail()
    await startRecording(user)
    emitDegradedActive()

    act(() => {
      mockApi.emitTranscriptionResult({
        channel: 'mic',
        text: 'línea degradada del micro',
        startMs: 0,
        endMs: 1000,
        receivedAtMs: 1100,
        isFinal: true,
        speaker: null,
        offsetSeconds: 0
      })
      mockApi.emitTranscriptionResult({
        channel: 'system',
        text: 'línea degradada del sistema',
        startMs: 1000,
        endMs: 2000,
        receivedAtMs: 2100,
        isFinal: true,
        speaker: null,
        offsetSeconds: 1
      })
    })

    // Las líneas se pintan sin huecos y sin etiqueta de hablante (speaker null)
    expect(await screen.findByText('línea degradada del micro')).toBeInTheDocument()
    expect(screen.getByText('línea degradada del sistema')).toBeInTheDocument()
    expect(screen.queryByText(/Hablante \d/)).not.toBeInTheDocument()
    // La grabación sigue operativa
    expect(screen.getByRole('button', { name: 'Detener' })).toBeInTheDocument()
  })

  // SPEC-022 · AC-08
  it('never shows the degraded alert during a normal session with working diarization', async () => {
    const user = userEvent.setup()
    renderDetail()
    await startRecording(user)

    act(() => {
      mockApi.emitTranscriptionStatus({ status: 'active' })
      mockApi.emitTranscriptionResult({
        channel: 'mic',
        text: 'línea con hablante identificado',
        startMs: 0,
        endMs: 1000,
        receivedAtMs: 1100,
        isFinal: true,
        speaker: 0,
        offsetSeconds: 0
      })
    })

    expect(await screen.findByText('línea con hablante identificado')).toBeInTheDocument()
    expect(screen.getByText('Hablante 1')).toBeInTheDocument()
    expect(screen.queryByTestId('transcription-degraded-alert')).not.toBeInTheDocument()
  })

  // SPEC-022-iter-1 (refuerzo de AC-06: el Alert SOLO en modo degradado real —
  // la rendición de un fallback que nunca abrió llega sin la marca y no debe
  // mostrar "la transcripción sigue funcionando" junto al error de conexión)
  it('does not show the degraded alert when the fallback surrender arrives without the degraded mark', async () => {
    const user = userEvent.setup()
    renderDetail()
    await startRecording(user)

    // Secuencia real de main tras el fix: reintento y rendición SIN degraded
    act(() => {
      mockApi.emitTranscriptionStatus({
        status: 'disconnected',
        error: {
          kind: 'deepgram-connection',
          message: 'Se perdió la conexión con Deepgram (código 1006). Reintentando la conexión…'
        }
      })
    })
    act(() => {
      mockApi.emitTranscriptionStatus({
        status: 'disconnected',
        error: {
          kind: 'deepgram-connection',
          message:
            'No se pudo restablecer la conexión con Deepgram (código 1006). La captura continúa sin transcripción; se conservan las líneas ya recibidas.'
        }
      })
    })

    // Aparece SOLO el error de conexión; jamás el Alert de modo degradado
    expect(
      await screen.findByText(/No se pudo restablecer la conexión con Deepgram/)
    ).toBeInTheDocument()
    expect(screen.queryByTestId('transcription-degraded-alert')).not.toBeInTheDocument()
    // La grabación sigue en curso (la rendición no la detiene)
    expect(screen.getByRole('button', { name: 'Detener' })).toBeInTheDocument()
  })
})
